sql:
SELECT vessel_name, vessel_type
FROM vessels
WHERE net_tonnage > 50000;

SELECT vessels.vessel_name, owners.owner_name
FROM vessels
INNER JOIN owners ON vessels.owner_id = owners.owner_id;

SELECT COUNT(*)
FROM vessels
WHERE vessel_type = 'ship' AND flag = 'Argentina';

SELECT DISTINCT owners.owner_name, owners.contact_email
FROM owners
INNER JOIN vessels ON owners.owner_id = vessels.owner_id;

SELECT vessel_class, COUNT(*) AS total_vessels
FROM vessels
GROUP BY vessel_class;

SELECT MAX(net_tonnage) 
FROM vessels 
WHERE vessel_class = 'Tanker';

SELECT vessel_name 
FROM vessels 
WHERE gross_tonnage = (SELECT MAX(gross_tonnage) FROM vessels);

SELECT owner_name AS name, contact_email AS email FROM owners
UNION
SELECT user_name AS name, email FROM users;

SELECT latitude, longitude
FROM vessel_positions
WHERE vessel_id = 0;
